sp_widget.client_script:
api.controller = function($scope, $http) {
    var c = this;

    // Instance ID - populated by server script
    c.instanceId = c.data.instanceId || 'UNKNOWN';
    var baseUrl = 'https://' + c.instanceId + '.service-now.com';

    // State
    c.os = 'mac';
    c.openLab = null;
    c.executing = false;
    c.showOAuthPanel = false;

    // OAuth credentials (entered by student)
    c.oauthCreds = {
        integration: {
            clientId: '',
            clientSecret: '',
            accessToken: ''
        },
        integrationAdmin: {
            clientId: '',
            clientSecret: '',
            accessToken: ''
        }
    };

    // ---- Lab and Test definitions ----
    c.labs = [{
            id: 'lab1',
            num: 1,
            title: 'Table settings',
            tests: [{
                    id: '1a',
                    description: 'Test access to the Table API for the Vehicle table',
                    method: 'GET',
                    authType: 'basic',
                    authUser: 'vehicle.integration',
                    endpoint: '/api/now/table/x_snc_vehicle_ma_0_vehicle?sysparm_limit=1'
                },
                {
                    id: '1b',
                    description: 'Test access to the Vehicles API for the Vehicle table',
                    method: 'GET',
                    authType: 'basic',
                    authUser: 'vehicle.integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                }
            ]
        },
        {
            id: 'lab2',
            num: 2,
            title: 'Access controls I',
            tests: [{
                    id: '2a',
                    description: 'Test access to the Vehicles API for vehicle.user',
                    method: 'GET',
                    authType: 'basic',
                    authUser: 'vehicle.user',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                },
                {
                    id: '2b',
                    description: 'Test access to the Vehicles API for vehicle.integration',
                    method: 'GET',
                    authType: 'basic',
                    authUser: 'vehicle.integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                }
            ]
        },
        {
            id: 'lab3',
            num: 3,
            title: 'Access controls II',
            tests: [{
                    id: '3a',
                    description: 'Test Get Vehicle (v2) for vehicle.integration',
                    method: 'GET',
                    authType: 'basic',
                    authUser: 'vehicle.integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                },
                {
                    id: '3b',
                    description: 'Test Get Vehicle (v2) for vehicle.integration_admin',
                    method: 'GET',
                    authType: 'basic',
                    authUser: 'vehicle.integration_admin',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                },
                {
                    id: '3c',
                    description: 'Test Create Vehicles (v2) for vehicle.integration',
                    method: 'POST',
                    authType: 'basic',
                    authUser: 'vehicle.integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicles',
                    body: {
                        mac: {
                            "vehicles": [{
                                "make": "Studebaker",
                                "model": "Avanti",
                                "vin": "WAUPFAFMXBA262342",
                                "year": "1964",
                                "country": "India",
                                "city": "Bangalore"
                            }]
                        },
                        win: {
                            "vehicles": [{
                                "make": "Peugeot",
                                "model": "308",
                                "vin": "FRAPFA4IXCB067223",
                                "year": "2024",
                                "country": "France",
                                "city": "Paris"
                            }]
                        }
                    }
                },
                {
                    id: '3d',
                    description: 'Test Create Vehicles (v2) for vehicle.integration_admin',
                    method: 'POST',
                    authType: 'basic',
                    authUser: 'vehicle.integration_admin',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicles',
                    body: {
                        mac: {
                            "vehicles": [{
                                "make": "Studebaker",
                                "model": "Avanti",
                                "vin": "WAUPFAFMXBA262342",
                                "year": "1964",
                                "country": "India",
                                "city": "Bangalore"
                            }]
                        },
                        win: {
                            "vehicles": [{
                                "make": "Peugeot",
                                "model": "308",
                                "vin": "FRAPFA4IXCB067223",
                                "year": "2024",
                                "country": "France",
                                "city": "Paris"
                            }]
                        }
                    }
                }
            ]
        },
        {
            id: 'lab4',
            num: 4,
            title: 'Access controls III',
            tests: [{
                    id: '4a',
                    description: 'Test Get Vehicle (v2) and access to PIN for vehicle.integration',
                    method: 'GET',
                    authType: 'basic',
                    authUser: 'vehicle.integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                },
                {
                    id: '4b',
                    description: 'Test Get Vehicle (v2) and access to PIN for vehicle.integration_admin',
                    method: 'GET',
                    authType: 'basic',
                    authUser: 'vehicle.integration_admin',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                }
            ]
        },
        {
            id: 'lab5',
            num: 5,
            title: 'OAuth 2.0',
            tests: [{
                    id: '5a',
                    description: 'Request an access token for vehicle.integration',
                    method: 'POST',
                    authType: 'oauth_token_request',
                    oauthProfile: 'integration',
                    endpoint: '/oauth_token.do'
                },
                {
                    id: '5b',
                    description: 'Test Get Vehicle (v3) with access token',
                    method: 'GET',
                    authType: 'bearer',
                    oauthProfile: 'integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                }
            ]
        },
        {
            id: 'lab6',
            num: 6,
            title: 'Authentication scopes',
            tests: [{
                    id: '6a',
                    description: 'Request a new access token for vehicle.integration associated with authentication scopes',
                    method: 'POST',
                    authType: 'oauth_token_request',
                    oauthProfile: 'integration',
                    endpoint: '/oauth_token.do'
                },
                {
                    id: '6b',
                    description: 'Test Get Vehicle (v3) with a new access token associated to authentication scopes',
                    method: 'GET',
                    authType: 'bearer',
                    oauthProfile: 'integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                },
                {
                    id: '6c',
                    description: 'Test Delete Vehicle (v3) with a read and update access token',
                    method: 'DELETE',
                    authType: 'bearer',
                    oauthProfile: 'integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/WAUPFAFMXBA262342'
                },
                {
                    id: '6d.i',
                    description: 'Request a new access token for vehicle.integration_admin',
                    method: 'POST',
                    authType: 'oauth_token_request',
                    oauthProfile: 'integrationAdmin',
                    endpoint: '/oauth_token.do'
                },
                {
                    id: '6d.ii',
                    description: 'Test Delete Vehicle (v3) with a create and delete access token',
                    method: 'DELETE',
                    authType: 'bearer',
                    oauthProfile: 'integrationAdmin',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/WAUPFAFMXBA262342'
                }
            ]
        },
        {
            id: 'lab7',
            num: 7,
            title: 'API Access Policies',
            tests: [{
                    id: '7a',
                    description: 'Test Get Vehicle (v3) with access token',
                    method: 'GET',
                    authType: 'bearer',
                    oauthProfile: 'integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                },
                {
                    id: '7b',
                    description: 'Test Get Vehicle (v3) using basic authentication',
                    method: 'GET',
                    authType: 'basic',
                    authUser: 'vehicle.integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/vehicles_api/vehicle/137FA90341E600811'
                }
            ]
        },
        {
            id: 'lab8',
            num: 8,
            title: 'API rate limits',
            tests: [{
                id: '8',
                description: 'Test Get Vehicle (v3). Execute test more than once',
                method: 'GET',
                authType: 'bearer',
                oauthProfile: 'integration',
                endpoint: '/api/x_snc_vehicle_ma_0/v3/vehicles_api/vehicle/137FA90341E600811'
            }]
        },
        {
            id: 'lab9',
            num: 9,
            title: 'Disable deprecated versions',
            tests: [{
                    id: '9a',
                    description: 'Test Get Vehicle (v3)',
                    method: 'GET',
                    authType: 'bearer',
                    oauthProfile: 'integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/v3/vehicles_api/vehicle/137FA90341E600811'
                },
                {
                    id: '9b',
                    description: 'Test Get Vehicle (v1)',
                    method: 'GET',
                    authType: 'bearer',
                    oauthProfile: 'integration',
                    endpoint: '/api/x_snc_vehicle_ma_0/v1/vehicles_api/vehicle/137FA90341E600811'
                }
            ]
        }
    ];

    // ---- OS toggle ----
    c.setOS = function(os) {
        c.os = os;
    };

    // ---- Lab accordion ----
    c.toggleLab = function(labId) {
        if (c.openLab === labId) {
            c.openLab = null;
            c.showOAuthPanel = false;
        } else {
            c.openLab = labId;
            var labNum = 0;
            c.labs.forEach(function(lab) {
                if (lab.id === labId) labNum = lab.num;
            });
            c.showOAuthPanel = labNum >= 5;
        }
    };

    // ---- Password lookup ----
    var passwords = {
        'vehicle.user': 'restapi9',
        'vehicle.admin': 'restapi9',
        'vehicle.integration': 'restapi9',
        'vehicle.integration_admin': 'restapi9'
    };

    // ---- Command generation ----
    c.getCommand = function(test) {
        if (c.os === 'mac') {
            return buildMacCommand(test);
        } else {
            return buildWinCommand(test);
        }
    };

    function buildMacCommand(test) {
        var url = baseUrl + test.endpoint;

        if (test.authType === 'oauth_token_request') {
            var profile = test.oauthProfile === 'integrationAdmin' ? 'integrationAdmin' : 'integration';
            var cid = c.oauthCreds[profile].clientId || '&lt;client_id_' + (profile === 'integrationAdmin' ? 'integration_admin' : 'integration') + '&gt;';
            var csec = c.oauthCreds[profile].clientSecret || '&lt;client_secret_' + (profile === 'integrationAdmin' ? 'integration_admin' : 'integration') + '&gt;';
            return "curl -X POST '" + url + "' \\\n" +
                "--data-urlencode 'grant_type=client_credentials' \\\n" +
                "--data-urlencode 'client_id=" + cid + "' \\\n" +
                "--data-urlencode 'client_secret=" + csec + "'";
        }

        if (test.authType === 'bearer') {
            var profile = test.oauthProfile === 'integrationAdmin' ? 'integrationAdmin' : 'integration';
            var token = c.oauthCreds[profile].accessToken || '&lt;access_token_' + (profile === 'integrationAdmin' ? 'integration_admin' : 'integration') + '&gt;';
            return "curl -X " + test.method + " '" + url + "' \\\n" +
                "--header 'Authorization: Bearer " + token + "'";
        }

        var cmd = "curl '" + url + "' \\\n--request " + test.method + " \\\n--user '" + test.authUser + ":" + passwords[test.authUser] + "'";

        if (test.body) {
            var bodyData = test.body.mac || test.body;
            cmd += " \\\n--header 'Content-Type: application/json' \\\n--data '" + JSON.stringify(bodyData, null, 4) + "'";
        }

        return cmd;
    }

    function buildWinCommand(test) {
        var url = baseUrl + test.endpoint;

        if (test.authType === 'oauth_token_request') {
            var profile = test.oauthProfile === 'integrationAdmin' ? 'integrationAdmin' : 'integration';
            var cid = c.oauthCreds[profile].clientId || '&lt;client_id_' + (profile === 'integrationAdmin' ? 'integration_admin' : 'integration') + '&gt;';
            var csec = c.oauthCreds[profile].clientSecret || '&lt;client_secret_' + (profile === 'integrationAdmin' ? 'integration_admin' : 'integration') + '&gt;';
            return "curl.exe -X POST '" + url + "' --data-urlencode 'grant_type=client_credentials' --data-urlencode 'client_id=" + cid + "' --data-urlencode 'client_secret=" + csec + "'";
        }

        if (test.authType === 'bearer') {
            var profile = test.oauthProfile === 'integrationAdmin' ? 'integrationAdmin' : 'integration';
            var token = c.oauthCreds[profile].accessToken || '&lt;access_token_' + (profile === 'integrationAdmin' ? 'integration_admin' : 'integration') + '&gt;';
            return "curl.exe -X " + test.method + " '" + url + "' --header 'Authorization: Bearer " + token + "'";
        }

        if (test.body) {
            var bodyData = test.body.win || test.body;
            var jsonStr = JSON.stringify(bodyData);
            var escapedJson = jsonStr.replace(/"/g, '""');
            return 'curl.exe --% "' + url + '" --request ' + test.method + ' --header "Content-Type: application/json" --user "' + test.authUser + ':' + passwords[test.authUser] + '" --data "' + escapedJson + '"';
        }

        return "curl.exe '" + url + "' --request " + test.method + " --user '" + test.authUser + ":" + passwords[test.authUser] + "'";
    }

    // ---- Copy to clipboard ----
    c.copyCommand = function(test, $event) {
        var cmd = c.getCommand(test);
        var textarea = document.createElement('textarea');
        textarea.value = cmd;
        textarea.style.position = 'fixed';
        textarea.style.opacity = '0';
        document.body.appendChild(textarea);
        textarea.select();
        document.execCommand('copy');
        document.body.removeChild(textarea);

        var btn = $event.currentTarget;
        var originalHTML = btn.innerHTML;
        btn.innerHTML = '<i class="fa fa-check"></i> Copied!';
        setTimeout(function() {
            btn.innerHTML = originalHTML;
        }, 1500);
    };

    // ---- Test execution ----
    c.executeTest = function(test) {
        c.executing = true;
        test.result = null;

        var payload = {
            action: 'execute_test',
            method: test.method,
            endpoint: test.endpoint,
            authType: test.authType
        };

        if (test.authType === 'basic') {
            payload.username = test.authUser;
            payload.password = passwords[test.authUser];
        } else if (test.authType === 'oauth_token_request') {
            var profile = test.oauthProfile === 'integrationAdmin' ? 'integrationAdmin' : 'integration';
            payload.clientId = c.oauthCreds[profile].clientId;
            payload.clientSecret = c.oauthCreds[profile].clientSecret;
            if (!payload.clientId || !payload.clientSecret) {
                test.result = {
                    error: true,
                    status: 'N/A',
                    body: 'ERROR: Please enter the Client ID and Client Secret in the OAuth Credentials panel above before requesting a token.'
                };
                c.executing = false;
                return;
            }
        } else if (test.authType === 'bearer') {
            var profile = test.oauthProfile === 'integrationAdmin' ? 'integrationAdmin' : 'integration';
            payload.accessToken = c.oauthCreds[profile].accessToken;
            if (!payload.accessToken) {
                test.result = {
                    error: true,
                    status: 'N/A',
                    body: 'ERROR: No access token available. Run the token request test first (e.g., Test 5a or 6a) to obtain a token, or paste one into the OAuth Credentials panel.'
                };
                c.executing = false;
                return;
            }
        }

        if (test.body) {
            payload.body = JSON.stringify(test.body.mac || test.body);
        }

        c.server.get(payload).then(function(response) {
            var data = response.data || response;
            var responseBody = data.responseBody || '';

            try {
                var parsed = JSON.parse(responseBody);
                responseBody = JSON.stringify(parsed, null, 2);
            } catch (e) {}

            test.result = {
                status: data.statusCode || 'Unknown',
                body: responseBody,
                error: false
            };

            if (test.authType === 'oauth_token_request') {
                try {
                    var tokenResponse = JSON.parse(data.responseBody || responseBody);
                    if (tokenResponse.access_token) {
                        var profile = test.oauthProfile === 'integrationAdmin' ? 'integrationAdmin' : 'integration';
                        c.oauthCreds[profile].accessToken = tokenResponse.access_token;
                    }
                } catch (e) {}
            }

            c.executing = false;
        });
    };
}

sp_widget.css:
.snu-lab-helper {
    max-width: 960px;
    margin: 0 auto;
    padding: 20px;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}
.snu-header {
    text-align: center;
    margin-bottom: 24px;
    padding-bottom: 16px;
    border-bottom: 2px solid #e0e0e0;
}
.snu-header h1 {
    font-size: 24px;
    font-weight: 600;
    color: #022D43;
    margin-bottom: 4px;
}
.snu-subtitle {
    font-size: 14px;
    color: #666;
    margin: 0;
}
.snu-os-toggle {
    text-align: center;
    margin-bottom: 20px;
}
.snu-os-toggle .btn {
    min-width: 160px;
    margin: 0 4px;
}
.snu-oauth-panel {
    background: #f8f9fa;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 16px 20px;
    margin-bottom: 20px;
}
.snu-oauth-panel h3 {
    font-size: 16px;
    font-weight: 600;
    margin-top: 0;
    margin-bottom: 8px;
    color: #022D43;
}
.snu-oauth-panel h4 {
    font-size: 14px;
    font-weight: 600;
    margin-top: 12px;
    margin-bottom: 8px;
    color: #495057;
}
.snu-oauth-panel .snu-note {
    font-size: 13px;
    color: #6c757d;
    margin-bottom: 12px;
}
.snu-oauth-panel .form-group {
    margin-bottom: 8px;
}
.snu-oauth-panel label {
    font-size: 12px;
    font-weight: 500;
    color: #495057;
    margin-bottom: 2px;
}
.snu-labs .panel {
    border-radius: 4px;
    margin-bottom: 4px;
}
.snu-lab-heading {
    cursor: pointer;
    padding: 12px 16px !important;
    background: #022D43 !important;
    color: #fff !important;
    border: none !important;
    transition: background 0.15s;
}
.snu-lab-heading:hover {
    background: #033B58 !important;
}
.snu-lab-heading .panel-title {
    font-size: 15px;
    font-weight: 500;
    color: #fff;
}
.snu-lab-heading .panel-title .fa {
    margin-right: 8px;
    width: 12px;
    text-align: center;
}
.snu-test {
    margin-bottom: 20px;
    padding-bottom: 20px;
    border-bottom: 1px solid #eee;
}
.snu-test:last-child {
    margin-bottom: 0;
    padding-bottom: 0;
    border-bottom: none;
}
.snu-test-header {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 10px;
}
.snu-test-id {
    font-weight: 700;
    font-size: 14px;
    color: #022D43;
    white-space: nowrap;
}
.snu-test-desc {
    font-size: 14px;
    color: #495057;
    flex: 1;
}
.snu-method-badge {
    font-size: 11px;
    font-weight: 600;
    text-transform: uppercase;
}
.snu-command-block {
    border: 1px solid #d1d5db;
    border-radius: 6px;
    overflow: hidden;
    margin-bottom: 10px;
}
.snu-command-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 4px 10px;
    background: #f1f3f5;
    border-bottom: 1px solid #d1d5db;
}
.snu-command-label {
    font-size: 12px;
    font-weight: 500;
    color: #6c757d;
}
.snu-copy-btn {
    font-size: 12px;
    background-color: #337ab7;
    color: #fff;
    border: 1px solid #2e6da4;
    padding: 5px 10px;
    border-radius: 3px;
}
.snu-copy-btn:hover,
.snu-copy-btn:focus {
    background-color: #286090;
    color: #fff;
    border-color: #204d74;
}
.snu-copy-btn i {
    color: #fff;
}
.snu-command-pre {
    background: #1e1e1e;
    color: #d4d4d4;
    margin: 0;
    padding: 12px 14px;
    font-size: 13px;
    line-height: 1.5;
    overflow-x: auto;
    white-space: pre-wrap;
    word-break: break-all;
    border: none;
    border-radius: 0;
}
.snu-test-actions {
    display: flex;
    align-items: center;
    gap: 12px;
}
.snu-verify-note {
    font-size: 12px;
}
.snu-results {
    margin-top: 10px;
    border: 1px solid #d1d5db;
    border-radius: 6px;
    overflow: hidden;
}
.snu-results-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 6px 10px;
    background: #f8f9fa;
    border-bottom: 1px solid #d1d5db;
}
.snu-results-pre {
    background: #fafafa;
    color: #333;
    margin: 0;
    padding: 12px 14px;
    font-size: 12px;
    line-height: 1.4;
    max-height: 400px;
    overflow: auto;
    border: none;
    border-radius: 0;
}

sp_widget.script:
(function() {
    // Try multiple approaches to get the instance name
    var instId = '';

    // Approach 1: instance_name property
    instId = gs.getProperty('instance_name') || '';

    // Approach 2: Parse from glide.servlet.uri
    if (!instId) {
        var uri = gs.getProperty('glide.servlet.uri') || '';
        var match = uri.match(/https?:\/\/([^.]+)/);
        if (match) {
            instId = match[1];
        }
    }

    // Approach 3: Parse from current request URL
    if (!instId) {
        try {
            var reqUrl = '';
            if (typeof g_request !== 'undefined' && g_request) {
                reqUrl = g_request.getRequestURL() + '';
            }
            if (reqUrl) {
                var urlMatch = reqUrl.match(/https?:\/\/([^.]+)/);
                if (urlMatch) {
                    instId = urlMatch[1];
                }
            }
        } catch(e) {}
    }

    data.instanceId = instId || 'UNKNOWN';

    if (input && input.action === 'execute_test') {
        var result = executeApiCall(input);
        data.statusCode = result.statusCode;
        data.responseBody = result.responseBody;
    }

    function executeApiCall(params) {
        var response = {
            statusCode: 0,
            responseBody: ''
        };

        try {
            var instanceName = data.instanceId;
            var fullUrl = 'https://' + instanceName + '.service-now.com' + params.endpoint;

            var rm = new sn_ws.RESTMessageV2();
            rm.setHttpMethod(params.method || 'GET');
            rm.setEndpoint(fullUrl);
            rm.setRequestHeader('Accept', 'application/json');

            if (params.authType === 'basic') {
                rm.setBasicAuth(params.username, params.password);
            } else if (params.authType === 'oauth_token_request') {
                rm.setHttpMethod('POST');
                rm.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
                var tokenBody = 'grant_type=client_credentials' +
                    '&client_id=' + encodeURIComponent(params.clientId) +
                    '&client_secret=' + encodeURIComponent(params.clientSecret);
                rm.setRequestBody(tokenBody);
            } else if (params.authType === 'bearer') {
                rm.setRequestHeader('Authorization', 'Bearer ' + params.accessToken);
            }

            if (params.body && params.authType !== 'oauth_token_request') {
                rm.setRequestHeader('Content-Type', 'application/json');
                rm.setRequestBody(params.body);
            }

            var httpResponse = rm.execute();
            response.statusCode = httpResponse.getStatusCode();
            response.responseBody = httpResponse.getBody();

        } catch (e) {
            response.statusCode = 0;
            response.responseBody = JSON.stringify({
                error: true,
                message: 'Execution error: ' + e.message
            });
        }

        return response;
    }
})();
